60	export async function generateImage({
61	  model: modelArg,
62	  prompt: promptArg,
63	  n = 1,
64	  maxImagesPerCall,
65	  size,
66	  aspectRatio,
67	  seed,
68	  providerOptions,
69	  maxRetries: maxRetriesArg,
70	  abortSignal,
71	  headers,
72	}: {
73	  /**
74	   * The image model to use.
75	   */
76	  model: ImageModel;
77	
78	  /**
79	   * The prompt that should be used to generate the image.
80	   */
81	  prompt: GenerateImagePrompt;
82	
83	  /**
84	   * Number of images to generate.
85	   */
86	  n?: number;
87	
88	  /**
89	   * Maximum number of images to generate in a single API call. If not provided, the model's default will be used.
90	   */
91	  maxImagesPerCall?: number;
92	
93	  /**
94	   * Size of the images to generate. Must have the format `{width}x{height}`. If not provided, the default size will be used.
95	   */
96	  size?: `${number}x${number}`;
97	
98	  /**
99	   * Aspect ratio of the images to generate. Must have the format `{width}:{height}`. If not provided, the default aspect ratio will be used.
100	   */
101	  aspectRatio?: `${number}:${number}`;
102	
103	  /**
104	   * Seed for the image generation. If not provided, the default seed will be used.
105	   */
106	  seed?: number;
