186	    const {
187	      prompt,
188	      n,
189	      size,
190	      aspectRatio,
191	      seed,
192	      providerOptions,
193	      headers,
194	      abortSignal,
195	      files,
196	      mask,
197	    } = options;
198	    const warnings: Array<SharedV3Warning> = [];
199	
200	    // Gemini does not support mask-based inpainting
201	    if (mask != null) {
202	      throw new Error(
