import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'This model does not support the `seed` option.',
      });
    }

    // Parse and validate provider options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const {
      size: providerSize,
      style,
      pixelDensity,
      ...remainingProviderOptions
    } = pixelartOptions ?? {};

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(providerSize ?? size ? { size: providerSize ?? size } : {}),
        ...(style ? { style } : {}),
        ...(pixelDensity != null ? { pixel_density: pixelDensity } : {}),
        ...remainingProviderOptions,
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

// limited version of the schema, focussed on what is needed for the implementation
// this approach limits breakages when the API changes and increases efficiency
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelartErrorDataSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.union([z.string(), z.number()]).nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelartErrorDataSchema>;

const pixelartFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelartErrorDataSchema,
  errorToMessage: data => data.error.message,
});

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * Image size, e.g. "512x512", "1024x1024".
         */
        size: z.string().nullish(),

        /**
         * Art style for the generated image.
         * - `pixel`: Classic pixel art style with clean, defined pixels.
         * - `retro`: Retro gaming inspired aesthetic with warm color palettes.
         * - `8bit`: 8-bit era inspired art with limited color depth.
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * Pixel density of the generated image (1-10).
         * Higher values produce more detailed pixels with finer granularity.
         * Lower values produce larger, blockier pixels.
         */
        pixelDensity: z.number().min(1).max(10).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

